import React from 'react';
import {
  SkeletonTable,
  SkeletonChart,
  SkeletonCard,
  SkeletonText,
} from '../components/SkeletonKit';

/**
 * Extract an HTTP status code from an error if present.
 * Looks for patterns like "HTTP 500", "status 502", or a numeric .status property.
 */
function extractStatusCode(error) {
  if (!error) return null;
  if (typeof error === 'object' && error.status && typeof error.status === 'number') return error.status;
  const msg = typeof error === 'string' ? error : error?.message || '';
  const match = msg.match(/(?:HTTP|status)\s*(\d{3})/i);
  return match ? parseInt(match[1], 10) : null;
}

/**
 * Return a user-friendly message based on status code.
 */
function friendlyMessage(statusCode, rawMsg) {
  if (statusCode >= 500 && statusCode < 600) {
    return 'The server encountered an issue. Our team monitors these errors and will investigate.';
  }
  if (statusCode === 429) return 'Too many requests. Please wait a moment and try again.';
  if (statusCode === 403) return 'You don\'t have permission to access this resource.';
  if (statusCode === 401) return 'Your session may have expired. Try refreshing the page.';
  if (rawMsg && rawMsg.includes('fetch') || rawMsg && rawMsg.includes('network') || rawMsg && rawMsg.includes('Network')) {
    return 'Unable to reach the server. Check your connection and try again.';
  }
  return null; // fall through to showing the raw message
}

const LoadingState = ({
  loading,
  error,
  empty,
  emptyMessage = 'No data available',
  type,
  rows = 5,
  cols = 4,
  height = 300,
  children,
  onRetry,
}) => {
  const styles = {
    container: {
      backgroundColor: '#0B0F14',
      color: '#FFFFFF',
      fontFamily: "'Plus Jakarta Sans', sans-serif",
      minHeight: '100%',
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      justifyContent: 'center',
      padding: 16,
      boxSizing: 'border-box',
    },
    surface: {
      backgroundColor: '#0F1620',
      border: '1px solid #1F2A37',
      borderRadius: 10,
      width: '100%',
      maxWidth: 960,
      boxSizing: 'border-box',
      padding: 24,
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      justifyContent: 'center',
      minHeight: 150,
    },
    emptyState: {
      color: '#6B7280',
      fontSize: 16,
      textAlign: 'center',
      fontWeight: 500,
      fontFamily: "'Plus Jakarta Sans', sans-serif",
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      gap: 12,
      userSelect: 'none',
    },
    emptyIcon: {
      width: 48,
      height: 48,
      fill: '#6B7280',
      opacity: 0.5,
    },
  };

  const [retryHover, setRetryHover] = React.useState(false);

  if (loading) {
    switch (type) {
      case 'table':
        return (
          <div style={styles.container}>
            <div style={styles.surface}>
              <SkeletonTable rows={rows} columns={cols} />
            </div>
          </div>
        );
      case 'chart':
        return (
          <div style={styles.container}>
            <div style={styles.surface}>
              <SkeletonChart height={height} />
            </div>
          </div>
        );
      case 'cards':
        return (
          <div style={styles.container}>
            <div style={styles.surface}>
              <SkeletonCard />
            </div>
          </div>
        );
      case 'text':
        return (
          <div style={styles.container}>
            <div style={styles.surface}>
              <SkeletonText />
            </div>
          </div>
        );
      default:
        return null;
    }
  }

  if (error) {
    const rawMsg = typeof error === 'string' ? error : error?.message || 'An error occurred';
    const statusCode = extractStatusCode(error);
    const friendly = friendlyMessage(statusCode, rawMsg);

    return (
      <div style={styles.container}>
        <div style={{
          maxWidth: 480,
          width: '100%',
          boxSizing: 'border-box',
          padding: 32,
          borderRadius: 14,
          backgroundColor: '#161B22',
          border: '1px solid #30363D',
          textAlign: 'center',
        }} role="alert" aria-live="assertive">
          {/* Warning icon */}
          <div style={{
            width: 48,
            height: 48,
            borderRadius: '50%',
            background: statusCode >= 500
              ? 'linear-gradient(135deg, rgba(248,81,73,0.12), rgba(210,153,34,0.12))'
              : 'linear-gradient(135deg, rgba(210,153,34,0.15), rgba(248,81,73,0.08))',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            margin: '0 auto 16px',
          }}>
            <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke={statusCode >= 500 ? '#F85149' : '#D29922'} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <circle cx="12" cy="12" r="10" />
              <line x1="12" y1="8" x2="12" y2="12" />
              <line x1="12" y1="16" x2="12.01" y2="16" />
            </svg>
          </div>

          {/* Title with optional status code */}
          <h3 style={{
            color: '#E6EDF3',
            fontSize: 17,
            fontWeight: 600,
            margin: '0 0 8px 0',
            fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
          }}>
            {statusCode
              ? `Unable to load data (${statusCode})`
              : 'Unable to load data'}
          </h3>

          {/* Friendly message */}
          <p style={{
            color: '#8B949E',
            fontSize: 13,
            margin: '0 0 20px 0',
            lineHeight: 1.6,
            fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
          }}>
            {friendly || rawMsg}
          </p>

          {/* Action row */}
          <div style={{ display: 'flex', gap: 10, justifyContent: 'center', flexWrap: 'wrap', marginBottom: statusCode >= 500 ? 12 : 0 }}>
            {onRetry && (
              <button
                type="button"
                onClick={onRetry}
                onMouseEnter={() => setRetryHover(true)}
                onMouseLeave={() => setRetryHover(false)}
                style={{
                  padding: '10px 24px',
                  borderRadius: 10,
                  border: 'none',
                  background: 'linear-gradient(135deg, #60A5FA, #A78BFA)',
                  color: '#ffffff',
                  fontSize: 13,
                  fontWeight: 600,
                  cursor: 'pointer',
                  fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
                  boxShadow: retryHover ? '0 4px 20px rgba(96, 165, 250, 0.35)' : '0 4px 16px rgba(96, 165, 250, 0.2)',
                  transition: 'box-shadow 0.15s',
                }}
                aria-label="Retry loading data"
              >
                Retry
              </button>
            )}
            {!onRetry && (
              <button
                type="button"
                onClick={() => window.location.reload()}
                onMouseEnter={() => setRetryHover(true)}
                onMouseLeave={() => setRetryHover(false)}
                style={{
                  padding: '10px 24px',
                  borderRadius: 10,
                  border: 'none',
                  background: 'linear-gradient(135deg, #60A5FA, #A78BFA)',
                  color: '#ffffff',
                  fontSize: 13,
                  fontWeight: 600,
                  cursor: 'pointer',
                  fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
                  boxShadow: retryHover ? '0 4px 20px rgba(96, 165, 250, 0.35)' : '0 4px 16px rgba(96, 165, 250, 0.2)',
                  transition: 'box-shadow 0.15s',
                }}
                aria-label="Reload the page"
              >
                Reload Page
              </button>
            )}
          </div>

          {/* Contact for server errors */}
          {statusCode >= 500 && (
            <p style={{
              color: '#484F58',
              fontSize: 11,
              margin: 0,
              fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
            }}>
              Persistent issue? Contact{' '}
              <a href="mailto:support@auraalpha.cc" style={{ color: '#58A6FF', textDecoration: 'none' }}>
                support@auraalpha.cc
              </a>
            </p>
          )}
        </div>
      </div>
    );
  }

  if (empty && !loading) {
    return (
      <div style={styles.container}>
        <div style={styles.emptyState} aria-live="polite" aria-busy="false">
          <svg
            aria-hidden="true"
            focusable="false"
            style={styles.emptyIcon}
            xmlns="http://www.w3.org/2000/svg"
            viewBox="0 0 24 24"
          >
            <path d="M12 2a10 10 0 1 0 10 10A10.011 10.011 0 0 0 12 2zm0 18a8 8 0 1 1 8-8 8.009 8.009 0 0 1-8 8zm-1-13h2v6h-2zm0 8h2v2h-2z" />
          </svg>
          {emptyMessage}
        </div>
      </div>
    );
  }

  return <>{children}</>;
};

export default LoadingState;
